
DO $$ BEGIN
  CREATE TYPE public.blog_category AS ENUM ('specialists', 'admins', 'parents', 'product');
EXCEPTION WHEN duplicate_object THEN null; END $$;

CREATE TABLE IF NOT EXISTS public.blog_posts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT NOT NULL UNIQUE,
  title TEXT NOT NULL,
  excerpt TEXT NOT NULL DEFAULT '',
  content TEXT NOT NULL DEFAULT '',
  category public.blog_category NOT NULL DEFAULT 'specialists',
  keywords TEXT[] NOT NULL DEFAULT '{}',
  cover_url TEXT,
  author TEXT NOT NULL DEFAULT 'Команда universum.',
  reading_minutes INT NOT NULL DEFAULT 5,
  published BOOLEAN NOT NULL DEFAULT true,
  published_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

GRANT SELECT ON public.blog_posts TO anon;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.blog_posts TO authenticated;
GRANT ALL ON public.blog_posts TO service_role;

ALTER TABLE public.blog_posts ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read published blog posts"
ON public.blog_posts FOR SELECT
USING (published = true);

CREATE POLICY "Admins can read all blog posts"
ON public.blog_posts FOR SELECT
TO authenticated
USING (public.has_role(auth.uid(), 'admin'::app_role));

CREATE POLICY "Admins can insert blog posts"
ON public.blog_posts FOR INSERT
TO authenticated
WITH CHECK (public.has_role(auth.uid(), 'admin'::app_role));

CREATE POLICY "Admins can update blog posts"
ON public.blog_posts FOR UPDATE
TO authenticated
USING (public.has_role(auth.uid(), 'admin'::app_role));

CREATE POLICY "Admins can delete blog posts"
ON public.blog_posts FOR DELETE
TO authenticated
USING (public.has_role(auth.uid(), 'admin'::app_role));

DROP TRIGGER IF EXISTS blog_posts_updated_at ON public.blog_posts;
CREATE TRIGGER blog_posts_updated_at
BEFORE UPDATE ON public.blog_posts
FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

CREATE INDEX IF NOT EXISTS blog_posts_published_idx ON public.blog_posts (published, published_at DESC);
CREATE INDEX IF NOT EXISTS blog_posts_category_idx ON public.blog_posts (category);

INSERT INTO public.blog_posts (slug, title, excerpt, content, category, keywords, reading_minutes, published_at)
VALUES
(
  'kak-provesti-ppk-v-shkole',
  'Как провести ППк в школе: пошаговый алгоритм',
  'Практический алгоритм проведения психолого-педагогического консилиума (ППк) в школе: подготовка, состав, документы, протокол и заключение. С опорой на Приказ Минпросвещения № 1082.',
  '<h2>Что такое ППк и зачем он нужен</h2><p>Психолого-педагогический консилиум (ППк) — это внутренняя форма взаимодействия специалистов образовательной организации, которая помогает выработать согласованную стратегию помощи ребёнку. Правовая основа — Приказ Минпросвещения России от 20.09.2013 № 1082 и локальный акт школы.</p><h2>Шаг 1. Состав консилиума</h2><p>В постоянный состав входят: председатель (обычно заместитель директора), педагог-психолог, учитель-логопед, учитель-дефектолог, социальный педагог, классный руководитель. По запросу — медицинский работник, тьютор, учителя-предметники.</p><h2>Шаг 2. Основания для проведения</h2><ul><li>Письменное обращение педагога или родителя</li><li>Результаты скрининга или диагностики</li><li>Плановый пересмотр индивидуального маршрута</li></ul><h2>Шаг 3. Подготовка документов</h2><p>До заседания собираются: письменное согласие родителя (законного представителя) на проведение ППк, педагогическая характеристика от классного руководителя, результаты диагностики от каждого специалиста, продукты деятельности ребёнка (тетради, работы).</p><h2>Шаг 4. Проведение заседания</h2><p>Каждый специалист представляет свои наблюдения и результаты. Обсуждаются сильные стороны ребёнка, зоны трудностей, ресурсы семьи. Формулируется общее заключение и рекомендации.</p><h2>Шаг 5. Оформление протокола и заключения</h2><p>Протокол включает: дату, состав присутствующих, повестку, выступления, решение. Заключение ППк содержит краткие выводы, направления коррекционной работы, рекомендации педагогам и родителям, сроки повторного рассмотрения.</p><h2>Шаг 6. Динамическое наблюдение</h2><p>Через 1–3 месяца проводится повторный ППк для оценки динамики. Если положительной динамики нет — ребёнку рекомендуется обследование на ПМПК.</p><h2>Типовые ошибки</h2><ul><li>Проводить ППк без письменного согласия родителя</li><li>Смешивать функции ППк и ПМПК</li><li>Формулировать «диагноз» вместо педагогических рекомендаций</li><li>Не фиксировать динамику</li></ul><p>В платформе universum. все шаги ППк автоматизированы: сбор согласий, шаблоны характеристик, электронные протоколы, автоматические напоминания о повторных заседаниях.</p>',
  'specialists',
  ARRAY['ППк','психолого-педагогический консилиум','школа','Приказ 1082','протокол ППк'],
  8,
  now() - interval '3 days'
),
(
  'sluzhba-soprovozhdeniya-po-prikazu-666',
  'Как организовать службу психолого-педагогического сопровождения по Приказу ДОНМ № 666',
  'Что должно быть в приказе, локальных актах и штатном расписании школы, чтобы служба психолого-педагогического сопровождения работала в соответствии с Приказом ДОНМ Москвы № 666.',
  '<h2>О чём Приказ № 666</h2><p>Приказ Департамента образования и науки города Москвы от 07.08.2018 № 666 «Об организации психолого-педагогического сопровождения обучающихся» устанавливает единый порядок работы школьных психологов, логопедов и дефектологов в образовательных организациях Москвы.</p><h2>Что нужно сделать администрации</h2><ol><li><strong>Издать приказ по школе</strong> о создании службы психолого-педагогического сопровождения (ППС) с назначением руководителя.</li><li><strong>Утвердить положение</strong> о службе ППС — цели, задачи, состав, регламент работы.</li><li><strong>Утвердить план работы</strong> службы на учебный год.</li><li><strong>Обеспечить помещения:</strong> кабинет психолога, логопедический кабинет, комната сенсорной разгрузки (по возможности).</li></ol><h2>Обязательные документы</h2><ul><li>Журнал учёта индивидуальных консультаций</li><li>Журнал учёта групповых занятий</li><li>Согласия родителей на психолого-педагогическое сопровождение</li><li>Индивидуальные карты сопровождения</li><li>Планы коррекционно-развивающей работы</li><li>Аналитические отчёты по итогам года</li></ul><h2>Нормативы нагрузки</h2><p>По Приказу № 666 педагог-психолог ведёт сопровождение не более 500 обучающихся, учитель-логопед — не более 25 детей одновременно, учитель-дефектолог — не более 20. Эти нормативы учитываются при формировании штатного расписания.</p><h2>Взаимодействие с ППМС-центрами</h2><p>Школа заключает соглашение о сотрудничестве с городским ППМС-центром. По сложным случаям (не менее чем через 1 месяц безуспешной внутришкольной работы) ребёнок направляется в центральную ПМПК.</p><h2>Как universum. упрощает работу</h2><p>Платформа автоматически формирует все обязательные журналы, ведёт учёт согласий, генерирует годовые отчёты по нагрузке специалистов и хранит данные в соответствии с ФЗ-152 (уровень защищённости УЗ-1).</p>',
  'admins',
  ARRAY['Приказ 666','ДОНМ','служба сопровождения','ППМС','психолог в школе'],
  7,
  now() - interval '10 days'
),
(
  'podgotovka-k-pmpk',
  'Подготовка к ПМПК: что взять и как настроить ребёнка',
  'Пошаговая инструкция для родителей: какие документы взять на ПМПК, как психологически подготовить ребёнка, чего ждать на комиссии и что делать после получения заключения.',
  '<h2>Что такое ПМПК</h2><p>Психолого-медико-педагогическая комиссия (ПМПК) — это независимая государственная комиссия, которая определяет, нужны ли ребёнку специальные образовательные условия. ПМПК не ставит медицинский диагноз, а даёт рекомендации по обучению.</p><h2>Документы, которые нужно взять</h2><ul><li>Паспорт родителя (законного представителя)</li><li>Свидетельство о рождении ребёнка</li><li>Направление от школы или детского сада (при наличии)</li><li>Заключение школьного ППк (если проводился)</li><li>Медицинская карта или выписки от врачей (невролог, психиатр, ЛОР, окулист)</li><li>Характеристика от воспитателя или учителя</li><li>Тетради, рисунки, поделки ребёнка</li><li>Логопедическое заключение (если есть)</li></ul><h2>Как психологически подготовить ребёнка</h2><ol><li>Расскажите заранее и спокойно: «Мы пойдём к добрым специалистам, они поиграют с тобой и зададут вопросы, чтобы помочь тебе лучше учиться».</li><li>Не пугайте комиссией и «врачами». Не говорите: «Если будешь плохо себя вести, тебя отправят в другую школу».</li><li>Выспитесь и покормите ребёнка перед выходом.</li><li>Возьмите любимую игрушку или книгу — для комфорта в очереди.</li><li>Оденьте ребёнка в удобную одежду, в которой он сможет свободно двигаться.</li></ol><h2>Как проходит комиссия</h2><p>Обследование занимает 40–90 минут. В кабинете обычно 3–5 специалистов: педагог-психолог, учитель-логопед, учитель-дефектолог, врач-психиатр, социальный педагог. Родитель присутствует всё время. Ребёнку предлагают выполнить задания на внимание, память, речь, мышление.</p><h2>Что важно знать</h2><ul><li>Родитель имеет право задавать вопросы и получать разъяснения по каждой рекомендации.</li><li>Заключение выдаётся в тот же день или в течение 5 рабочих дней.</li><li>Заключение носит <strong>рекомендательный</strong> характер — принятие рекомендаций остаётся за родителем.</li><li>Если вы не согласны, можно обратиться в центральную ПМПК или на повторное обследование.</li></ul><h2>После получения заключения</h2><p>Передайте копию заключения в школу или детский сад. Администрация обязана в течение 10 рабочих дней организовать создание специальных условий, указанных в заключении: адаптированную программу, работу со специалистами, тьютора и т.д.</p><h2>Расширенный гайд</h2><p>Полная пошаговая инструкция с примерами формулировок, шаблонами заявлений и юридическими правами родителя — на странице <a href="/guides/pmpk-preparation">Подготовка к ПМПК</a>.</p>',
  'parents',
  ARRAY['ПМПК','подготовка к комиссии','документы на ПМПК','рекомендации родителям'],
  6,
  now() - interval '20 days'
),
(
  'kak-ponyat-chto-rebenku-nuzhen-logoped',
  'Как понять, что ребёнку нужен логопед: нормы речи 3–7 лет',
  'Возрастные нормы речевого развития от 3 до 7 лет. Простой чек-лист для родителей: когда обращаться к логопеду и какие сигналы нельзя пропустить.',
  '<h2>Почему возрастные нормы важны</h2><p>Речь развивается по определённым этапам. Отставание на 6–12 месяцев считается вариантом нормы, но задержка более года — повод обратиться к логопеду. Чем раньше начать работу, тем быстрее и легче ребёнок навёрстывает.</p><h2>3 года</h2><ul><li>Словарь: 800–1000 слов</li><li>Говорит фразами из 3–5 слов</li><li>Использует местоимения «я», «ты», «мы»</li><li>Задаёт вопросы «что?», «где?», «куда?»</li><li>Может произносить с ошибками «р», «л», «ш», «ж», «щ», «ц» — это норма</li></ul><p><strong>Тревога:</strong> ребёнок общается жестами, не строит фразы, речь непонятна даже родителям.</p><h2>4 года</h2><ul><li>Словарь: 1500–2000 слов</li><li>Использует сложные предложения</li><li>Пересказывает короткие сказки</li><li>Правильно произносит большинство звуков, кроме «р», «л», шипящих</li><li>Задаёт вопросы «почему?», «зачем?»</li></ul><p><strong>Тревога:</strong> речь малопонятна посторонним, ребёнок путает слоги, не запоминает стихи.</p><h2>5 лет</h2><ul><li>Словарь: 2500–3000 слов</li><li>Строит связный рассказ по картинке</li><li>Правильно произносит все звуки, кроме «р» и «л» (могут ставиться до 5,5 лет)</li><li>Согласует слова в роде, числе, падеже</li></ul><p><strong>Тревога:</strong> есть искажения звуков (межзубный «с», горловой «р»), ребёнок «глотает» окончания, не может пересказать простую историю.</p><h2>6–7 лет</h2><ul><li>Словарь: 3500+ слов</li><li>Правильно произносит все звуки родного языка</li><li>Различает похожие звуки на слух (б-п, д-т, с-ш)</li><li>Делит слова на слоги, выделяет первый и последний звук</li><li>Строит развёрнутые рассказы, использует сложноподчинённые предложения</li></ul><p><strong>Тревога:</strong> сохраняются нарушения звукопроизношения, ребёнок не готов к анализу и синтезу звуков — это прямой путь к дисграфии и дислексии в школе.</p><h2>Красные флаги в любом возрасте</h2><ul><li>Ребёнок не реагирует на речь — <em>консультация ЛОР и сурдолога</em></li><li>Резко замолчал после освоенной речи</li><li>Заикание, повторение слогов, «застревание» на звуках</li><li>Ринолалия (гнусавый голос)</li><li>Голосовые нарушения — хриплый, слабый голос</li></ul><h2>Что делать</h2><p>Обратитесь к логопеду в детском саду, поликлинике или ППМС-центре. Первичная консультация обычно бесплатна. Логопед проведёт диагностику и скажет, нужны ли занятия и в каком формате: индивидуально, в группе или дома с родителями по рекомендациям.</p>',
  'parents',
  ARRAY['логопед','нормы речи','речевое развитие','когда идти к логопеду','дети 3-7 лет'],
  5,
  now() - interval '30 days'
)
ON CONFLICT (slug) DO NOTHING;
